import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { insureServiceStrings } from '../../config';
import { insureUtilStrings, insureUtil } from '../../../utils';
import { Subheader } from '../../../../includes';
import { KnowledgeArea } from '../../../Home/KnowledeArea';
import { TextField, Button, CircularProgress, Typography } from '@material-ui/core';
import { insureServiceActions } from '../../actions';
import { appActions, alertAction } from '../../../../../actions';


const style = theme => ({
    root: {
    },
    container : {
        display : "flex",
        flexDirection : "column",
        padding : 20,
        minHeight : 200,
        marginTop : 100,
        marginBottom : 50,
        [theme.breakpoints.up("sm")] : {
            margin : 100,
        },
        [theme.breakpoints.up("md")] : {
            margin : "100px 200px",
        },
    },
    text : {
        display : "flex",
        flex : 1,
    },
    verifyBtn : {
        padding : 15,
        marginTop : 5,
        backgroundColor : insureUtil.getTheme().secondary,
        color : insureUtil.getTheme().primary,
    },
    verifyContainer : {
        display : "flex",
        justifyContent : "center",
        alignItems : "center"
    },
    infoContainer : {
        border : "solid 1px "+insureUtil.getTheme().secondary,
        borderRadius : 10,
        display : "flex",
    },
    header : {
        backgroundColor: insureUtil.getTheme().secondary,
        borderRadius: "10px 0px 0px 10px",
        padding: 20,
        paddingRight: 20,
        color: insureUtil.getTheme().white,
    },
    info : {
        padding : "20px 0px",
        marginLeft : 10,
    }
})
class _Verify extends Component {
    constructor(props) {
        super(props);
        this.state = {
            phone : "",
            loading : false,
        }
    }
    
    onChange(e){
        const value = e.target.value;
        this.setState({phone: value});
    }
    verifyNumber(){
        this.setState({loading : true});
        const { dispatch } = this.props;
        const {phone} = this.state;
        if(String(phone).length < 10){
            this.setState({loading : false, result : null, noResponse :false});
            appActions.showSnackbar(
                alertAction.error("Invalid phone number")
            )(dispatch);
            return;
        }
        insureServiceActions.verifyPhoneNumber(phone, (done, result)=>{
            if(done) {
                if(result) this.setState({loading : false, result, noResponse : false});
                else this.setState({loading : false, noResponse : true, result});
            }else this.setState({loading : false})
        })(dispatch);
    }
    render() {
        const {
            classes,
            [insureUtilStrings.subheadImage] : subheadImage,
        } = this.props;
        const {phone, loading, result, noResponse} = this.state;
        console.log(result);
        return (
            <div className={classes.root}>
                <Subheader
                    title="Verify Subscription"
                    image_url={subheadImage}
                    />
                <div className={classes.container}>
                    <div className={classes.verifyContainer}>
                        <TextField
                            value={phone}
                            margin="normal"
                            className={classes.text}
                            onChange={this.onChange.bind(this)}
                            label="Phone Number"
                            placeholder="Phone number"
                            variant="outlined"/>
                        <div><Button
                            variant="contained"
                            disabled={loading}
                            onClick={this.verifyNumber.bind(this)}
                            className={classes.verifyBtn}>
                                {loading && <CircularProgress size={20}/>} Verify Number
                            </Button></div>
                    </div>
                    {noResponse && <div style={{marginTop : 20}}>
                        <Typography component="div" paragraph className={classes.infoContainer}>
                            <Typography className={classes.header}>Response :</Typography>
                            <Typography className={classes.info}>This ID is not a subscriber</Typography>
                        </Typography>
                    </div>}
                    {result && <div>
                        <Typography paragraph variant="h4">{result.lastName +", "+result.firstName}</Typography>
                        <Typography component="div" paragraph className={classes.infoContainer}>
                            <Typography className={classes.header}>Phone :</Typography>
                            <Typography className={classes.info}>{result.phone}</Typography>
                        </Typography>
                        <Typography component="div" paragraph className={classes.infoContainer}>
                            <Typography className={classes.header}>Status :</Typography>
                            <Typography className={classes.info}>{
                                result.suspended ? "SUSPENDED" : (result.expDate && new Date(result.expDate) > new Date() ? "ACTIVE" : "INACTIVE")
                            }</Typography>
                        </Typography>
                    </div>}
                </div>
                <KnowledgeArea/>
            </div>
        );
    }
}


_Verify.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({insureUtilReducer}) => ({
    [insureUtilStrings.subheadImage] : insureUtilReducer[insureUtilStrings.subheadImage],
})


export const Verify = connect(mapStateToProps)(withStyles(style)(_Verify));
export {Verify as default}